import{_ as e,o as l,c as n,ag as o}from"./chunks/framework.CvgP6Fyv.js";const k=JSON.parse('{"title":"Keycloak SPI 扩展开发指南","description":"","frontmatter":{},"headers":[{"level":1,"title":"Keycloak SPI 扩展开发指南","slug":"keycloak-spi-扩展开发指南","link":"#keycloak-spi-扩展开发指南","children":[{"level":2,"title":"项目简介","slug":"项目简介","link":"#项目简介","children":[]},{"level":2,"title":"扩展类型","slug":"扩展类型","link":"#扩展类型","children":[{"level":3,"title":"SPI User Storage Extension","slug":"spi-user-storage-extension","link":"#spi-user-storage-extension","children":[]},{"level":3,"title":"SPI Event Listener Extension","slug":"spi-event-listener-extension","link":"#spi-event-listener-extension","children":[]},{"level":3,"title":"SPI SM Crypto Extension","slug":"spi-sm-crypto-extension","link":"#spi-sm-crypto-extension","children":[]}]},{"level":2,"title":"版本对比","slug":"版本对比","link":"#版本对比","children":[]},{"level":2,"title":"核心功能","slug":"核心功能","link":"#核心功能","children":[]},{"level":2,"title":"技术支持","slug":"技术支持","link":"#技术支持","children":[]},{"level":2,"title":"快速开始","slug":"快速开始","link":"#快速开始","children":[]},{"level":2,"title":"注意事项","slug":"注意事项","link":"#注意事项","children":[]},{"level":2,"title":"免责声明","slug":"免责声明","link":"#免责声明","children":[]}]}],"relativePath":"dev/keycloak-extension/index.md","filePath":"dev/keycloak-extension/index.md"}'),r={name:"dev/keycloak-extension/index.md"};function i(s,t,a,g,c,d){return l(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="keycloak-spi-扩展开发指南" tabindex="-1">Keycloak SPI 扩展开发指南 <a class="header-anchor" href="#keycloak-spi-扩展开发指南" aria-label="Permalink to &quot;Keycloak SPI 扩展开发指南&quot;">​</a></h1><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p>Keycloak 扩展开发指南是面向开发者打造的 Keycloak 扩展开发参考文档，涵盖 SPI 扩展、自定义认证流程、用户存储集成等核心功能，提供完整的开发示例和最佳实践，帮助开发者快速构建符合企业需求的 Keycloak 扩展。</p><p>本项目提供标准化的 Keycloak 扩展开发方案、详细的实现文档及配套示例代码，支持开发者快速完成各类 Keycloak 扩展的开发、测试与部署，大幅提升开发效率。</p><h2 id="扩展类型" tabindex="-1">扩展类型 <a class="header-anchor" href="#扩展类型" aria-label="Permalink to &quot;扩展类型&quot;">​</a></h2><p>根据您的需求，选择适合的 Keycloak 扩展类型：</p><h3 id="spi-user-storage-extension" tabindex="-1">SPI User Storage Extension <a class="header-anchor" href="#spi-user-storage-extension" aria-label="Permalink to &quot;SPI User Storage Extension&quot;">​</a></h3><ul><li><strong>功能</strong>：实现 Keycloak 的用户存储 SPI，用于从外部数据库中读取用户信息</li><li><strong>支持数据库</strong>：MySQL、SQL Server、Oracle、达梦、金仓、OceanBase、GaussDB</li><li><strong>核心特性</strong>：支持多种数据库类型，提供灵活的用户存储能力，允许企业将现有的用户数据无缝集成到 Keycloak 中</li><li><strong>文档链接</strong>：<a href="./spi-user-storage-extension.html">SPI User Storage Extension</a></li></ul><h3 id="spi-event-listener-extension" tabindex="-1">SPI Event Listener Extension <a class="header-anchor" href="#spi-event-listener-extension" aria-label="Permalink to &quot;SPI Event Listener Extension&quot;">​</a></h3><ul><li><strong>功能</strong>：实现 Keycloak 的事件监听器 SPI，用于将 Keycloak 的事件发送到消息队列</li><li><strong>支持消息队列</strong>：Kafka、RabbitMQ、RocketMQ</li><li><strong>核心特性</strong>：支持多种消息队列系统，提供可扩展的架构，允许添加新的消息通道实现</li><li><strong>文档链接</strong>：<a href="./spi-event-listener-extension.html">SPI Event Listener Extension</a></li></ul><h3 id="spi-sm-crypto-extension" tabindex="-1">SPI SM Crypto Extension <a class="header-anchor" href="#spi-sm-crypto-extension" aria-label="Permalink to &quot;SPI SM Crypto Extension&quot;">​</a></h3><ul><li><strong>功能</strong>：实现 Keycloak 的加密 SPI，集成了中国国家标准密码算法（国密算法）</li><li><strong>支持算法</strong>：SM2（椭圆曲线公钥密码算法）、SM3（密码杂凑算法）、SM4（分组密码算法）</li><li><strong>核心特性</strong>：为 Keycloak 提供了符合中国密码标准的加密能力，使 Keycloak 能够在需要使用国密算法的场景中正常工作</li><li><strong>文档链接</strong>：<a href="./spi-sm-crypto-extension.html">SPI SM Crypto Extension</a></li></ul><h2 id="版本对比" tabindex="-1">版本对比 <a class="header-anchor" href="#版本对比" aria-label="Permalink to &quot;版本对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>SPI User Storage Extension</th><th>SPI Event Listener Extension</th><th>SPI SM Crypto Extension</th></tr></thead><tbody><tr><td><strong>主要功能</strong></td><td>外部用户存储集成</td><td>事件监听与消息队列集成</td><td>国密算法集成</td></tr><tr><td><strong>依赖</strong></td><td>目标数据库驱动</td><td>消息队列客户端</td><td>Bouncy Castle 库</td></tr><tr><td><strong>配置方式</strong></td><td>Keycloak 管理控制台</td><td>代码硬编码（建议通过组件配置管理）</td><td>Keycloak 管理控制台</td></tr><tr><td><strong>部署方式</strong></td><td>JAR 文件放入 standalone/deployments 目录</td><td>JAR 文件放入 standalone/deployments 目录</td><td>JAR 文件放入 standalone/deployments 目录</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><p><strong>Keycloak 扩展开发</strong></p><p><strong>核心开发功能：</strong></p><p>专为企业级 Keycloak 定制开发深度打造，一站式提供多种 SPI 扩展实现，开箱即用、零代码快速集成企业现有系统，完美支撑身份认证、事件处理、加密需求等多场景，解决 Keycloak 原生功能不足、定制复杂等核心痛点。</p><ul><li><strong>01：用户存储扩展</strong> — 支持从外部数据库读取用户信息，兼容多种数据库类型，包括 MySQL、SQL Server、Oracle、达梦、金仓、OceanBase 和 GaussDB，实现企业现有用户系统与 Keycloak 的无缝集成。</li><li><strong>02：事件监听器扩展</strong> — 将 Keycloak 的事件（如用户登录、登出、管理操作等）发送到消息队列，支持 Kafka、RabbitMQ 和 RocketMQ，便于进行审计、监控或其他业务处理。</li><li><strong>03：国密算法扩展</strong> — 集成中国国家标准密码算法（国密算法），包括 SM2、SM3 和 SM4，使 Keycloak 能够在需要使用国密算法的场景中正常工作，如政府、金融等对密码算法有特殊要求的领域。</li><li><strong>04：灵活的扩展架构</strong> — 提供可扩展的架构设计，允许开发者根据业务需求添加新的功能和支持新的服务，如添加新的数据库类型、消息队列系统或密码算法。</li><li><strong>05：完整的开发示例</strong> — 提供详细的代码实现和配置示例，帮助开发者快速理解和使用 Keycloak 扩展，减少开发和调试时间。</li><li><strong>06：标准化部署方案</strong> — 提供标准的部署方式，支持将扩展 JAR 文件放入 Keycloak 的 standalone/deployments 目录，实现快速部署和集成。</li></ul><h2 id="技术支持" tabindex="-1">技术支持 <a class="header-anchor" href="#技术支持" aria-label="Permalink to &quot;技术支持&quot;">​</a></h2><ul><li><strong>技术支持</strong>：北京必码科技工作室</li><li><strong>官方文档</strong>：<a href="https://bima.cc" target="_blank" rel="noreferrer">https://bima.cc</a></li><li><strong>官方店铺</strong>：<a href="https://bima.taobao.com" target="_blank" rel="noreferrer">https://bima.taobao.com</a></li><li><strong>联系邮箱</strong>：<a href="mailto:bima.cc@qq.com" target="_blank" rel="noreferrer">bima.cc@qq.com</a></li><li><strong>联系微信</strong>：e18929958</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><ol><li><strong>选择扩展类型</strong>：根据您的需求选择合适的 Keycloak 扩展类型</li><li><strong>查看文档</strong>：点击上方对应扩展类型的链接查看详细文档</li><li><strong>环境准备</strong>：按照文档要求准备 JDK、Keycloak 等环境</li><li><strong>编译构建</strong>：使用 Maven 编译构建扩展项目</li><li><strong>部署扩展</strong>：将编译好的 JAR 文件放入 Keycloak 的 standalone/deployments 目录</li><li><strong>配置扩展</strong>：根据文档要求在 Keycloak 管理控制台中配置扩展</li><li><strong>测试验证</strong>：执行相应的测试验证扩展功能是否正常</li></ol><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li><strong>环境要求</strong>：确保 JDK 版本为 11 或更高，Keycloak 版本为 17.0.0 或更高</li><li><strong>依赖管理</strong>：根据扩展类型安装相应的依赖，如数据库驱动、消息队列客户端或 Bouncy Castle 库</li><li><strong>配置管理</strong>：生产环境中建议通过 Keycloak 的组件配置管理扩展设置，避免硬编码配置</li><li><strong>性能优化</strong>：根据实际使用场景优化扩展性能，如使用连接池管理数据库连接、批量处理事件等</li><li><strong>安全性</strong>：注意密码存储安全、连接安全和权限控制，避免安全漏洞</li><li><strong>测试验证</strong>：在生产环境部署前，进行充分的测试，确保扩展功能正常</li><li><strong>版本兼容性</strong>：注意 Keycloak 版本与扩展版本的兼容性，避免因版本不匹配导致的问题</li><li><strong>文档维护</strong>：维护详细的文档，记录配置选项和使用方法</li><li><strong>监控管理</strong>：定期监控扩展的运行状态，及时发现和解决问题</li><li><strong>合规性</strong>：确保扩展的使用符合相关法律法规和行业规范</li></ul><h2 id="免责声明" tabindex="-1">免责声明 <a class="header-anchor" href="#免责声明" aria-label="Permalink to &quot;免责声明&quot;">​</a></h2><p>本项目基于 GitHub 开源软件进行定制化开发，旨在为企业和开发者提供更便捷的项目基座解决方案。使用本项目时，请务必了解以下免责声明：</p><ol><li><strong>开源基础</strong>：本项目基于 GitHub 开源软件构建，遵循原开源协议的相关规定。</li><li><strong>定制开发</strong>：我们对原开源软件进行了定制和扩展，以提供更优质的开发体验和功能支持。</li><li><strong>责任限制</strong>：对于使用本项目可能产生的任何直接或间接的经济损失、数据丢失或其他问题，北京必码科技工作室不承担任何责任。</li><li><strong>使用建议</strong>：在生产环境中使用本项目前，请进行充分的测试和验证，确保其符合您的业务需求和安全要求。</li><li><strong>技术支持</strong>：我们提供技术支持服务，但不保证解决所有可能出现的问题。</li><li><strong>合规使用</strong>：用户应确保在使用本项目时遵守相关法律法规和行业规范，不得用于任何违法或违规用途。</li></ol>',28)])])}const u=e(r,[["render",i]]);export{k as __pageData,u as default};
